import{_ as a,o as e,c as r,ag as i}from"./chunks/framework.BZohXCq9.js";const p=JSON.parse('{"title":"介绍","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md"}'),d={name:"guide/index.md"};function o(l,t,n,h,s,u){return e(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="介绍" tabindex="-1">介绍 <a class="header-anchor" href="#介绍" aria-label="Permalink to &quot;介绍&quot;">​</a></h1><p>ah-util 是一个轻量级的前端工具库，专注于为现代前端开发提供简洁、高效、类型安全的工具函数。</p><h2 id="特性" tabindex="-1">特性 <a class="header-anchor" href="#特性" aria-label="Permalink to &quot;特性&quot;">​</a></h2><ul><li><strong>零依赖</strong> - 不依赖任何外部库，保持最小 bundle 体积</li><li><strong>类型安全</strong> - 完整的 TypeScript 类型定义</li><li><strong>Tree-shaking</strong> - 支持按需导入，自动排除未使用的代码</li><li><strong>多环境</strong> - 支持浏览器、Node.js、微信小程序等环境</li><li><strong>多格式</strong> - 提供 ESM、CJS、UMD 三种导出格式</li></ul><h2 id="模块概览" tabindex="-1">模块概览 <a class="header-anchor" href="#模块概览" aria-label="Permalink to &quot;模块概览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块</th><th>描述</th></tr></thead><tbody><tr><td><a href="/api/type">类型判断</a></td><td>判断各种数据类型，如字符串、数字、数组等</td></tr><tr><td><a href="/api/string">字符串</a></td><td>字符串处理，如去空格、格式化、命名转换等</td></tr><tr><td><a href="/api/array">数组</a></td><td>数组操作，如去重、分块、交集、并集等</td></tr><tr><td><a href="/api/object">对象</a></td><td>对象操作，如深拷贝、属性获取、合并等</td></tr><tr><td><a href="/api/browser">浏览器</a></td><td>浏览器相关工具，如防抖、节流、存储等</td></tr></tbody></table><h2 id="为什么选择-ah-util" tabindex="-1">为什么选择 ah-util？ <a class="header-anchor" href="#为什么选择-ah-util" aria-label="Permalink to &quot;为什么选择 ah-util？&quot;">​</a></h2><p>相比 lodash 等大型工具库，ah-util 专注于提供最常用的功能，体积更小、加载更快。同时，我们保持 API 的简洁性和一致性，让开发者能够快速上手。</p>',8)])])}const _=a(d,[["render",o]]);export{p as __pageData,_ as default};
